// Получаем все входные данные
const items = $input.all();

if (items.length === 0) {
  return [];
}

// Разделяем: строки из таблицы и исходное сообщение
const rows = items.filter(item => item.json.user_id); // строки из Google Sheets
const originalMessage = items.find(item => item.json.message); // исходное сообщение

if (rows.length === 0) {
  // Если нет строк из БД, возвращаем пустой массив
  return [];
}

// Сортируем строки по timestamp (от новых к старым)
rows.sort((a, b) => {
  const timeA = new Date(a.json.timestamp);
  const timeB = new Date(b.json.timestamp);
  return timeB - timeA;
});

// Берем самую свежую запись
const latestRow = rows[0];

// Добавляем к ней исходное сообщение (если оно есть)
if (originalMessage) {
  latestRow.json.originalMessage = originalMessage.json.message;
  latestRow.json.originalText = originalMessage.json.message?.text;
}

// Возвращаем обогащенный результат
return [latestRow];

