// Получаем текст сообщения напрямую из Telegram Trigger
const triggerData = $('Telegram Trigger').first().json;
const messageText = triggerData.message?.text || '';

// Инициализируем результат
const result = {
  extractedInn: null,
  extractedContract: null,
  hasInnOrContract: false,
  originalText: messageText
};

// Регулярное выражение для ИНН (10-12 цифр)
const innPattern = /(\d{10,12})/g;

// ВСЕ форматы номеров договоров (кроме чистых цифр)
const contractPatterns = [
  // Основные форматы СДЭК
  /([A-Z0-9]{2,3}-[A-Z0-9]{2,4}-\d{1,4})/gi,           // SZ-LBS2-21, SZ-KSD284-161, SZ-DLP4-31
  /(СЗ-РФ-[A-Z0-9]{2,5}-\d{1,4})/gi,                    // СЗ-РФ-LBS2-12, СЗ-РФ-ЛБС-33
  /(СЗ-РФ-ЛБС-\d{1,4})/gi,                               // СЗ-РФ-ЛБС-33
  /(СЗ-РФ-9ИИ-\d{1,4})/gi,                               // СЗ-РФ-9ИИ-1
  /(ДЛП\d{2,4})/gi,                                      // ДЛП280, ДЛП17, ДЛП109
  /(ЛБС\d{2,4})/gi,                                      // ЛБС68, ЛБС29, ЛБС92
  /(ИМ\d{5,14})/gi,                                      // ИМ1231247522, ИМ122962
  /(IM-[A-Z0-9]{2,5}-\d{1,4})/gi,                        // IM-DLP58-213, IM-LBS2-329
  /(IM-KSD284-\d{1,4})/gi,                               // IM-KSD284-66
  /(IM-NN259-\d{1,4})/gi,                                // IM-NN259-30
  /(KU-[A-Z0-9]{2,5}-\d{1,4})/gi,                        // KU-DLP58-71, KU-LBS2-124
  /(KU-KSD284-\d{1,4})/gi,                               // KU-KSD284-101
  /(KU-NN259-\d{1,4})/gi,                                // KU-NN259-72
  /(КУ-РФ-[A-Z0-9]{2,5}-\d{1,4})/gi,                     // КУ-РФ-ЛБС-17, КУ-РФ-LBS2-84
  /(ИМ-РФ-[A-Z0-9]{2,5}-\d{1,4})/gi,                     // ИМ-РФ-LBS2-90, ИМ-РФ-ЛБС-130
  /(НДИМ\d{5,14})/gi,                                    // НДИМ12367272
  /(НДДЛП\d{2,4})/gi,                                    // НДДЛП117
  /(ИМ\d{2,4})/gi,                                       // ИМ32658, ИМ24312
  /(KU-[A-Z0-9]{2,4}-\d{1,4})/gi,                        // KU-DLP4-67
  /(IM-DLP4-\d{1,4})/gi,                                 // IM-DLP4-34
  /(IM-DLP58-\d{1,4})/gi,                                // IM-DLP58-6
  /(ИМ-РФ-ДЛП-\d{1,4})/gi,                               // ИМ-РФ-ДЛП-11
  /(ИМ-РФ-9ИИ-\d{1,4})/gi,                               // ИМ-РФ-9ИИ-1
  /(СЗ-РФ-9ИИ-\d{1,4})/gi,                               // СЗ-РФ-9ИИ-1
  /(ИМ\d{5,10})/gi,                                      // ИМ1231247522
  /(IM-LBS2-\d{1,4})/gi,                                 // IM-LBS2-329
  /(СЗ-РФ-ЛБС-\d{1,4})/gi,                               // СЗ-РФ-ЛБС-33
  /(СЗ-РФ-LBS2-\d{1,4})/gi,                              // СЗ-РФ-LBS2-12
  /(SZ-[A-Z0-9]{2,4}-\d{1,4})/gi,                        // SZ-LBS2-21
  /(ИМ\d{5,10})/gi,                                      // ИМ1231247522
  /(IM-[A-Z0-9]{2,5}-\d{1,4})/gi,                        // IM-DLP58-213
  /(KU-[A-Z0-9]{2,5}-\d{1,4})/gi,                        // KU-DLP58-71
  /(КУ-РФ-[A-Z0-9]{2,5}-\d{1,4})/gi,                     // КУ-РФ-ЛБС-17
  /(ИМ-РФ-[A-Z0-9]{2,5}-\d{1,4})/gi,                     // ИМ-РФ-LBS2-90
  /(НДИМ\d{5,14})/gi,                                    // НДИМ12367272
  /(НДДЛП\d{2,4})/gi                                     // НДДЛП117
];

// Сначала ищем ИНН
const innMatches = messageText.match(innPattern);
if (innMatches && innMatches.length > 0) {
  result.extractedInn = innMatches[0];
  result.hasInnOrContract = true;
}

// Потом ищем номер договора по паттернам
for (const pattern of contractPatterns) {
  const contractMatches = messageText.match(pattern);
  if (contractMatches && contractMatches.length > 0) {
    result.extractedContract = contractMatches[0];
    result.hasInnOrContract = true;
    break;
  }
}

// Только если не нашли ни ИНН, ни договор - ищем чистые цифры
if (!result.hasInnOrContract && messageText) {
  const pureDigitsPattern = /(\d{5,})/g;
  const digitsMatches = messageText.match(pureDigitsPattern);
  if (digitsMatches && digitsMatches.length > 0) {
    // Проверяем, не является ли это ИНН (10-12 цифр)
    if (digitsMatches[0].length >= 10 && digitsMatches[0].length <= 12) {
      result.extractedInn = digitsMatches[0];
      result.hasInnOrContract = true;
    } else {
      result.extractedPossible = digitsMatches[0];
    }
  }

  // Ищем любую комбинацию букв и цифр
  if (!result.hasInnOrContract) {
    const anyNumberPattern = /[A-Z0-9]{5,}/gi;
    const anyMatches = messageText.match(anyNumberPattern);
    if (anyMatches && anyMatches.length > 0) {
      result.extractedPossible = anyMatches[0];
    }
  }
}

return result;

