// Парсим comment, получаем старого и нового менеджера
const comment = $('Code: последнее состояние').item.json.comment || '';
const newId = $('Telegram Trigger').item.json.message.text.trim();
const lines = comment.split('\n');
let oldManager = '', newManager = '';
for (const line of lines) {
  if (line.startsWith('old:')) oldManager = line.substring(4);
  if (line.startsWith('new:')) newManager = line.substring(4);
}

return [{
  user_id: $('Code: последнее состояние').item.json.user_id,
  oldManager,
  newManager,
  newId
}];

const clients = $input.all();
