const input = $input.body;
const chatId = $('Switch: Упаковка').first().json.callback_query.from.id
const callbackData = $('Switch: Упаковка').first().json.callback_query.data
const messageId = $('Switch: Упаковка').first().json.callback_query.message.message_id // может быть undefined

if (!chatId || !callbackData) {
  throw new Error('Нет данных');
}

let itemId, currentQty, actionType;

if (callbackData.startsWith('item_')) {
  // Первый показ карточки
  itemId = callbackData.replace('item_', '');
  currentQty = 1;
  actionType = 'new';
} else if (callbackData.startsWith('inc:') || callbackData.startsWith('dec:')) {
  // Изменение количества
  const parts = callbackData.split(':');
  const action = parts[0]; // 'inc' или 'dec'
  itemId = parts[1];
  currentQty = parseInt(parts[2], 10);
  actionType = 'edit';

  if (action === 'inc') {
    currentQty += 1;
  } else if (action === 'dec') {
    currentQty = Math.max(1, currentQty - 1);
  }
} else {
  throw new Error('Неизвестный тип колбэка');
}

// Получаем товар из каталога
const catalogData = $('Каталог товаров2').first().json;
let foundItem = null;
for (const cat in catalogData.categories) {
  const item = catalogData.categories[cat].find(i => i.id === itemId);
  if (item) {
    foundItem = item;
    break;
  }
}
if (!foundItem) {
  throw new Error(`Товар с id ${itemId} не найден`);
}

// Формируем клавиатуру с актуальным количеством
const keyboard = [
  [
    { text: '➖', callback_data: `dec:${itemId}:${currentQty}` },
    { text: `${currentQty}`, callback_data: 'noop' },
    { text: '➕', callback_data: `inc:${itemId}:${currentQty}` }
  ],
  [
    { text: '✅ Добавить в корзину', callback_data: `add:${itemId}:${currentQty}` }
  ],
  [
    { text: '◀️ Назад', callback_data: `cat_${foundItem.category}` }
  ]
];

const text = `📦 **${foundItem.name}**\\n💰 Цена: ${foundItem.price} руб.\\n\\nКоличество: ${currentQty}`;

if (actionType === 'new') {
  // Отправка нового сообщения
  return [{
    json: {
      chatId,
      text,
      parse_mode: 'Markdown',
      reply_markup: { inline_keyboard: keyboard }
    }
  }];
} else {
  // Редактирование существующего
  if (!messageId) throw new Error('Нет messageId для редактирования');
  return [{
    json: {
      chatId,
      messageId,
      text,
      parse_mode: 'Markdown',
      reply_markup: { inline_keyboard: keyboard }
    }
  }];
}

