rows.forEach(row => {
  const item = row.json;
  const id = item.item_id;
  if (!itemsMap[id]) {
    itemsMap[id] = {
      name: item.name,
      price: parseFloat(item.price),
      quantity: 0
    };
  }
  itemsMap[id].quantity += parseInt(item.quantity, 10);
});

// Преобразуем в массив cartItems
