rowNumbers.sort((a, b) => b - a);
// Возвращаем каждый номер как отдельный элемент
return rowNumbers.map(num => ({ json: { row_number: num } }));

const { chatId, cartItems } = $input.first().json;
if (!cartItems || cartItems.length === 0) {
  return [{
    json: {
      chatId,
      text: '🛒 Ваша корзина пуста',
      parse_mode: 'Markdown',
      reply_markup: {
        inline_keyboard: [[{ text: '📦 В каталог', callback_data: 'packaging_paid' }]]
      }
    }
  }];
}

let total = 0;
let text = '🛒 Ваша корзина:\\n\\n';
cartItems.forEach(item => {
  text += `📦 ${item.name}\\n`;
  text += `   ${item.quantity} шт × ${item.price} руб = ${item.quantity * item.price} руб\\n`;
  total += item.quantity * item.price;
});
text += `\\nИтого: ${total} руб`;

// Создаём клавиатуру с кнопками для каждого товара (опционально) и общими действиями
// Для простоты добавим кнопки "Оформить", "Очистить", "Продолжить"
const keyboard = [
  [{ text: '✅ Оформить заказ', callback_data: 'checkout' }],
  [{ text: '🗑️ Очистить корзину', callback_data: 'clear_cart' }],
  [{ text: '📦 Продолжить выбор', callback_data: 'packaging_paid' }]
];

// Можно добавить кнопки для удаления каждого товара, но это сложнее. Пока ограничимся очисткой.

return [{
  json: {
    chatId,
    text,
    parse_mode: 'Markdown',
    reply_markup: { inline_keyboard: keyboard }
  }
}];

const rows = $input.all(); // результат чтения
const chatId = rows[0]?.json.user_id; // можно взять из первой строки, но лучше передать отдельно
// Предположим, что chatId и callbackData передаются в $json из предыдущего узла (например, через Merge)
// Упростим: будем получать chatId из первого элемента, а callbackData будем брать из $('Switch: Упаковка').first().json.callback_query.data

const callbackData = $('Switch: Упаковка').first().json.callback_query.data;
const cart = {};

rows.forEach(row => {
  const id = row.json.item_id;
  if (!id) return;
  if (!cart[id]) {
    cart[id] = {
      name: row.json.name,
      price: parseFloat(row.json.price),
      quantity: 0
    };
  }
  cart[id].quantity += parseInt(row.json.quantity) || 0;
});

return [{
  json: {
    chatId,
    callbackData,
    cart,
    cartItems: Object.entries(cart).map(([id, item]) => ({ id, ...item }))
  }
}];

// Получаем все строки из входа
const items = $input.all();
// Извлекаем row_number, отбрасываем пустые
const rowNumbers = items.map(item => item.json.row_number).filter(n => n);
// Сортируем по убыванию (важно!)
rowNumbers.sort((a, b) => b - a);
// Возвращаем каждый номер как отдельный элемент
return rowNumbers.map(num => ({ json: { row_number: num } }));

// Текущее время в UTC
const now = new Date();
const utcTime = now.getTime() + (now.getTimezoneOffset() * 60 * 1000); // смещение к UTC

// Применяем смещение +3 часа (Москва)
const mskTime = new Date(utcTime + 3 * 60 * 60 * 1000);

const month = mskTime.getUTCMonth();  // 0 – январь, 1 – февраль, 2 – март, ...
const day = mskTime.getUTCDate();
const year = mskTime.getUTCFullYear();

// Форматируем дату как ДД.ММ.ГГГГ для удобства
const currentDateStr = `${day.toString().padStart(2, '0')}.${(month+1).toString().padStart(2, '0')}.${year}`;

// Множество допустимых комбинаций "месяц-день" (месяцы от 0)
const validDates = new Set([
  '2-7', '2-8', '2-9', '2-14', '2-15', '2-21', '2-22', '2-28', '2-29',
  '3-4', '3-5', '3-11', '3-12', '3-18', '3-19', '3-25', '3-26',
  '4-1', '4-2', '4-3', '4-9', '4-10', '4-11', '4-16', '4-17', '4-23', '4-24', '4-30', '4-31',
  '5-6', '5-7', '5-12', '5-13', '5-14', '5-20', '5-21', '5-27', '5-28',
  '6-4', '6-5', '6-11', '6-12', '6-18', '6-19', '6-25', '6-26',
  '7-1', '7-2', '7-8', '7-9', '7-15', '7-16', '7-22', '7-23', '7-29', '7-30',
  '8-5', '8-6', '8-12', '8-13', '8-19', '8-20', '8-26', '8-27',
  '9-3', '9-4', '9-10', '9-11', '9-17', '9-18', '9-24', '9-25', '9-31',
  '10-1', '10-4', '10-7', '10-8', '10-14', '10-15', '10-21', '10-22', '10-28', '10-29',
  '11-5', '11-6', '11-12', '11-13', '11-19', '11-20', '11-26', '11-27', '11-31'
]);

const isSpecialDay = validDates.has(`${month}-${day}`);

// Возвращаем массив с объектом
return [{
  json: {
    isSpecialDay: isSpecialDay,
    currentDate: currentDateStr,
    month: month,
    day: day,
    year: year
  }
}];

